"(function(){
    var _OrigAudio = window.Audio;
    window.Audio = function(src) {
        var audio = new _OrigAudio(src);
        try {
            window.webkit.messageHandlers.PoilinkSDK.postMessage({
                action: 'preloadSound',
                src: audio.src
            });
        } catch(e){}
        var _origPlay = audio.play.bind(audio);
        audio.play = function(){
            try {
                window.webkit.messageHandlers.PoilinkSDK.postMessage({
                    action: 'playSound',
                    src: audio.src,
                    volume: audio.volume
                });
            } catch(e){}
            return Promise.resolve();
        };
        return audio;
    };
    window.Audio.prototype = _OrigAudio.prototype;
})();"

"(function() {
    window.PoilinkSDK = window.PoilinkSDK || {};

    const pending = new Map();
    let nextCallbackId = 1;

    window.PoilinkSDK.closeWebView = function() {
        window.webkit.messageHandlers.PoilinkSDK.postMessage({action: 'closeWebView'});
    };

    window.PoilinkSDK.notifyMissionChallenge = function(missionId) {
        window.webkit.messageHandlers.PoilinkSDK.postMessage({
            action: 'notifyMissionChallenge',
            missionId: missionId
        });
    };

    window.PoilinkSDK.onItemRewardClaimed = function(grantId, itemCode, quantity, missionCode) {
        window.webkit.messageHandlers.PoilinkSDK.postMessage({
            action: 'onItemRewardClaimed',
            grantId: grantId,
            itemCode: itemCode,
            quantity: quantity,
            missionCode: missionCode || ''
        });
    };

    window.PoilinkSDK.notifyReady = function() {
        window.webkit.messageHandlers.PoilinkSDK.postMessage({action: 'notifyReady'});
    };

    window.PoilinkSDK.refreshAuthCookie = function() {
        return new Promise(function(resolve, reject) {
            const callbackId = nextCallbackId++;
            pending.set(callbackId, { resolve: resolve, reject: reject });
            window.webkit.messageHandlers.PoilinkSDK.postMessage({
                action: 'refreshAuthCookie',
                callbackId: callbackId
            });
        });
    };

    window.PoilinkSDK.__onRefreshAuthCookieComplete = function(callbackId, resultJson) {
        const handler = pending.get(callbackId);
        if (!handler) return;
        pending.delete(callbackId);
        const result = resultJson || {};
        if (result.code === 0) {
            handler.resolve();
        } else {
            handler.reject({ code: result.code || 1099, message: result.message || '' });
        }
    };
})();"

"if (typeof AbortSignal !== 'undefined' && !AbortSignal.any) {
    AbortSignal.any = function(signals) {
        const controller = new AbortController();
        for (const signal of signals) {
            if (signal.aborted) {
                controller.abort(signal.reason);
                break;
            }
            signal.addEventListener('abort', () => {
                controller.abort(signal.reason);
            }, { once: true });
        }
        return controller.signal;
    };
}"
